#include <stdio.h>
#include <stdlib.h>

int main(){
    const int MAX = 1000000;
    char *isPrime = (char*)calloc(MAX+1, sizeof(char));
    int *pref = (int*)malloc((MAX+1)*sizeof(int));
    for(int i=2;i<=MAX;i++) isPrime[i]=1;
    for(int p=2;p*p<=MAX;p++) if(isPrime[p]) for(int q=p*p;q<=MAX;q+=p) isPrime[q]=0;
    pref[0]=0; pref[1]=0;
    for(int i=2;i<=MAX;i++) pref[i]=pref[i-1]+isPrime[i];
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int X,Y; scanf("%d %d",&X,&Y);
        if(pref[X]<=Y) printf("Chef\n"); else printf("Divyam\n");
    }
    free(isPrime); free(pref);
    return 0;
}

